import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GeneratedImage {
  url: string;
  id: string;
}

export enum AppStatus {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  ANALYZING = 'ANALYZING',
  GENERATING = 'GENERATING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

export interface AppState {
  originalImage: string | null;
  extractedPrompt: string;
  variants: GeneratedImage[];
  status: AppStatus;
  error: string | null;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

/**
 * Helper to convert File or Blob to base64
 */
export const fileToDataUrl = (file: File | Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Extracts base64 content from Data URL
 */
const getBase64FromDataUrl = (dataUrl: string) => {
  return dataUrl.split(',')[1];
};

export const extractPromptFromImage = async (base64Image: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `Analyze this image in extreme detail. 
  Describe the style, lighting, color palette, main subjects, composition, and mood. 
  Create a concise but highly descriptive text prompt (max 100 words) that could be used by an AI image generator 
  to recreate a similar version of this image. Do not include introductory text, just provide the prompt.`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: getBase64FromDataUrl(base64Image), mimeType: 'image/png' } },
        { text: prompt }
      ]
    },
    config: {
        temperature: 0.7,
        topP: 0.8,
        topK: 40
    }
  });

  return response.text || "Could not extract prompt.";
};

export const generateImageVariant = async (prompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `Create a professional high-resolution artistic variation of this: ${prompt}` }]
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  // gemini-2.5-flash-image returns the image in candidates[0].content.parts
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data received from API");
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "px-6 py-2.5 rounded-lg font-medium transition-all duration-200 flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-500/20",
    secondary: "bg-slate-700 hover:bg-slate-600 text-slate-100 border border-slate-600",
    danger: "bg-red-600 hover:bg-red-500 text-white",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      ) : null}
      {children}
    </button>
  );
};

import React, { useState, useCallback } from 'react';
import { AppStatus, AppState, GeneratedImage } from './types';
import { fileToDataUrl, extractPromptFromImage, generateImageVariant } from './services/geminiService';
import { Button } from './components/Button';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    originalImage: null,
    extractedPrompt: '',
    variants: [],
    status: AppStatus.IDLE,
    error: null,
  });

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      setState(prev => ({ ...prev, status: AppStatus.UPLOADING, error: null }));
      const dataUrl = await fileToDataUrl(file);
      setState(prev => ({ 
        ...prev, 
        originalImage: dataUrl, 
        status: AppStatus.IDLE 
      }));
    } catch (err) {
      setState(prev => ({ 
        ...prev, 
        status: AppStatus.ERROR, 
        error: "Failed to load image. Please try again." 
      }));
    }
  };

  const processImage = async () => {
    if (!state.originalImage) return;

    try {
      // Step 1: Analyze & Extract Prompt
      setState(prev => ({ ...prev, status: AppStatus.ANALYZING, error: null }));
      const prompt = await extractPromptFromImage(state.originalImage);

      setState(prev => ({ ...prev, extractedPrompt: prompt, status: AppStatus.GENERATING }));

      // Step 2: Generate 2 Variants
      // We run these in parallel for efficiency
      const variantPromises = [
        generateImageVariant(prompt),
        generateImageVariant(prompt + " with subtle lighting changes and enhanced details")
      ];

      const [v1, v2] = await Promise.all(variantPromises);

      const newVariants: GeneratedImage[] = [
        { id: 'v1', url: v1 },
        { id: 'v2', url: v2 }
      ];

      setState(prev => ({ 
        ...prev, 
        variants: newVariants, 
        status: AppStatus.SUCCESS 
      }));

    } catch (err: any) {
      console.error(err);
      setState(prev => ({ 
        ...prev, 
        status: AppStatus.ERROR, 
        error: err.message || "An unexpected error occurred during processing." 
      }));
    }
  };

  const resetApp = () => {
    setState({
      originalImage: null,
      extractedPrompt: '',
      variants: [],
      status: AppStatus.IDLE,
      error: null,
    });
  };

  return (
    <div className="min-h-screen pb-12">
      {/* Header */}
      <header className="py-8 px-4 text-center">
        <h1 className="text-4xl md:text-5xl font-bold bg-gradient-to-r from-blue-400 to-emerald-400 bg-clip-text text-transparent">
          Visionary Re-Imagine
        </h1>
        <p className="mt-4 text-slate-400 max-w-2xl mx-auto text-lg">
          Upload any image to decode its artistic DNA and generate two unique AI-reimagined variations.
        </p>
      </header>

      <main className="max-w-6xl mx-auto px-4 space-y-8">

        {/* Upload Section */}
        {state.status === AppStatus.IDLE && !state.originalImage && (
          <div className="flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-3xl p-12 glass-panel transition-all hover:border-blue-500/50">
            <div className="w-16 h-16 bg-blue-500/10 rounded-full flex items-center justify-center mb-6">
              <svg className="w-8 h-8 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
              </svg>
            </div>
            <h2 className="text-xl font-semibold mb-2">Upload your inspiration</h2>
            <p className="text-slate-500 mb-6">Drag and drop or click to choose a photo</p>
            <input 
              type="file" 
              accept="image/*" 
              onChange={handleImageUpload} 
              className="hidden" 
              id="image-upload" 
            />
            <label htmlFor="image-upload">
              <Button as="span" className="cursor-pointer">Select Image</Button>
            </label>
          </div>
        )}

        {/* Processing State */}
        {(state.status === AppStatus.ANALYZING || state.status === AppStatus.GENERATING) && (
          <div className="glass-panel rounded-3xl p-12 text-center space-y-6 animate-pulse">
            <div className="w-20 h-20 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto"></div>
            <div>
              <h2 className="text-2xl font-bold text-blue-400">
                {state.status === AppStatus.ANALYZING ? "Decoding Visual DNA..." : "Generating New Realities..."}
              </h2>
              <p className="text-slate-400 mt-2">
                {state.status === AppStatus.ANALYZING 
                  ? "Gemini is extracting colors, styles, and composition details." 
                  : "We're crafting two unique variations based on the extracted prompt."}
              </p>
            </div>
          </div>
        )}

        {/* Results Section */}
        {(state.originalImage || state.status === AppStatus.SUCCESS) && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

            {/* Original Image Card */}
            <div className="glass-panel rounded-3xl p-6 h-fit sticky top-8">
              <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
                <span className="w-2 h-2 bg-blue-500 rounded-full"></span>
                Original Input
              </h3>
              <div className="rounded-2xl overflow-hidden shadow-2xl bg-slate-900 border border-slate-700">
                <img src={state.originalImage!} alt="Original" className="w-full object-cover" />
              </div>

              {state.status === AppStatus.IDLE && (
                <div className="mt-6 space-y-3">
                  <Button onClick={processImage} className="w-full">
                    Start Re-Imagining
                  </Button>
                  <Button onClick={resetApp} variant="secondary" className="w-full">
                    Choose Another
                  </Button>
                </div>
              )}

              {state.extractedPrompt && (
                <div className="mt-6 p-4 rounded-xl bg-slate-900/50 border border-slate-700">
                  <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Decoded Prompt</p>
                  <p className="text-sm text-slate-300 leading-relaxed italic">
                    "{state.extractedPrompt}"
                  </p>
                </div>
              )}
            </div>

            {/* Generated Variants Grid */}
            <div className="lg:col-span-2 space-y-8">
              {state.status === AppStatus.SUCCESS ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {state.variants.map((variant, index) => (
                    <div key={variant.id} className="glass-panel rounded-3xl overflow-hidden group">
                      <div className="relative aspect-square bg-slate-900">
                         <img 
                          src={variant.url} 
                          alt={`Variant ${index + 1}`} 
                          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" 
                        />
                        <div className="absolute top-4 left-4">
                          <span className="px-3 py-1 bg-black/50 backdrop-blur-md rounded-full text-xs font-bold text-white border border-white/20">
                            VARIATION {index + 1}
                          </span>
                        </div>
                      </div>
                      <div className="p-4 flex justify-between items-center">
                        <span className="text-slate-400 text-sm">AI Re-Imagined</span>
                        <a 
                          href={variant.url} 
                          download={`variant-${index + 1}.png`}
                          className="text-blue-400 hover:text-blue-300 transition-colors"
                        >
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                          </svg>
                        </a>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                state.status === AppStatus.IDLE && state.originalImage && (
                  <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-800 rounded-3xl text-slate-600">
                    <svg className="w-12 h-12 mb-4 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" />
                    </svg>
                    <p className="font-medium">Click "Start Re-Imagining" to begin processing</p>
                  </div>
                )
              )}

              {state.status === AppStatus.SUCCESS && (
                <div className="flex justify-center pt-4">
                  <Button onClick={resetApp} variant="secondary" className="px-12">
                    Start a New Project
                  </Button>
                </div>
              )}
            </div>

          </div>
        )}

        {/* Error State */}
        {state.status === AppStatus.ERROR && (
          <div className="bg-red-500/10 border border-red-500/50 p-6 rounded-2xl text-center">
            <h3 className="text-red-400 font-bold text-lg mb-2">Something went wrong</h3>
            <p className="text-red-200/70 mb-6">{state.error}</p>
            <Button onClick={resetApp} variant="danger">Try Again</Button>
          </div>
        )}
      </main>

      {/* Footer Info */}
      <footer className="mt-20 border-t border-slate-800 pt-8 text-center text-slate-500 text-sm">
        <p>Powered by Gemini 3 Flash & 2.5 Flash Image Generation Models</p>
        <div className="mt-2 flex justify-center gap-4">
          <span>Creative Suite</span>
          <span>•</span>
          <span>High Performance AI</span>
          <span>•</span>
          <span>Visual Analysis</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

