import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

/**
 * Helper to convert File or Blob to base64
 */
export const fileToDataUrl = (file: File | Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Extracts base64 content from Data URL
 */
const getBase64FromDataUrl = (dataUrl: string) => {
  return dataUrl.split(',')[1];
};

export const extractPromptFromImage = async (base64Image: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `Analyze this image in extreme detail. 
  Describe the style, lighting, color palette, main subjects, composition, and mood. 
  Create a concise but highly descriptive text prompt (max 100 words) that could be used by an AI image generator 
  to recreate a similar version of this image. Do not include introductory text, just provide the prompt.`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: getBase64FromDataUrl(base64Image), mimeType: 'image/png' } },
        { text: prompt }
      ]
    },
    config: {
        temperature: 0.7,
        topP: 0.8,
        topK: 40
    }
  });

  return response.text || "Could not extract prompt.";
};

export const generateImageVariant = async (prompt: string, styleSuffix: string = ''): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const finalPrompt = styleSuffix 
    ? `Create a professional high-resolution artistic variation of this: ${prompt}. Apply style: ${styleSuffix}`
    : `Create a professional high-resolution artistic variation of this: ${prompt}`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: finalPrompt }]
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9"
      }
    }
  });

  // gemini-2.5-flash-image returns the image in candidates[0].content.parts
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data received from API");
};

