                <label htmlFor="image-upload">
                  <Button as="span" className="cursor-pointer">Select Image</Button>
                </label>
              </div>
            )}

            {(state.originalImage || state.status === AppStatus.SUCCESS) && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Original View */}
                <div className="glass-panel rounded-3xl p-6 h-fit sticky top-8">
                  <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
                    <span className="w-2 h-2 bg-blue-500 rounded-full"></span>
                    Original Input
                  </h3>
                  <div className="rounded-2xl overflow-hidden shadow-2xl bg-slate-900 border border-slate-700">
                    <img src={state.originalImage!} alt="Original" className="w-full object-cover" />
                  </div>

                  {state.status === AppStatus.IDLE && (
                    <div className="mt-6 space-y-3">
                      <Button onClick={processVisionary} className="w-full">
                        Analyze & Generate
                      </Button>
                    </div>
                  )}

                  {state.extractedPrompt && (
                    <div className="mt-6 p-4 rounded-xl bg-slate-900/50 border border-slate-700">
                      <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Decoded Prompt</p>
                      <p className="text-sm text-slate-300 leading-relaxed italic">
                        "{state.extractedPrompt}"
                      </p>
                    </div>
                  )}
                </div>

                {/* Results View */}
                <div className="lg:col-span-2">
                  <ResultsGrid status={state.status} variants={state.variants} />
                </div>
              </div>
            )}
          </div>
        )}

        {/* TAB 2: CREATIVE PROMPT */}
        {state.activeTab === 'text' && (
          <div className="space-y-8">
            <div className="glass-panel rounded-3xl p-8 max-w-3xl mx-auto border border-purple-500/20 shadow-xl shadow-purple-500/5">
              <h2 className="text-xl font-bold mb-4 flex items-center gap-3">
                <span className="p-2 bg-purple-500/10 rounded-lg">
                  <svg className="w-5 h-5 text-purple-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                  </svg>
                </span>
                Text to Image
              </h2>
              <textarea 
                placeholder="Describe what you want to see... e.g., 'A futuristic cyberpunk marketplace with neon signs and flying cars in heavy rain'"
                className="w-full h-32 bg-slate-900/50 border border-slate-700 rounded-2xl p-4 text-slate-200 focus:outline-none focus:ring-2 focus:ring-purple-500/50 resize-none transition-all"
                value={state.manualPrompt}
                onChange={(e) => setState(prev => ({ ...prev, manualPrompt: e.target.value }))}
                disabled={state.status === AppStatus.GENERATING}
              />
              <div className="mt-6 flex justify-end">
                <Button 
                  onClick={processCreative} 
                  disabled={!state.manualPrompt.trim()}
                  isLoading={state.status === AppStatus.GENERATING}
                  className="bg-purple-600 hover:bg-purple-500"
                >
                  Generate Variants
                </Button>
              </div>
            </div>

            {state.status === AppStatus.SUCCESS && state.variants.length > 0 && (
              <div className="pt-4">
                 <ResultsGrid status={state.status} variants={state.variants} />
              </div>
            )}
          </div>
        )}

        {/* Shared Processing State Overlay */}
        {(state.status === AppStatus.ANALYZING || state.status === AppStatus.GENERATING) && (
          <div className="glass-panel rounded-3xl p-12 text-center space-y-6 animate-pulse border-blue-500/20">
            <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto shadow-lg shadow-blue-500/20"></div>
            <div>
              <h2 className="text-2xl font-bold text-blue-400">
                {state.status === AppStatus.ANALYZING ? "Analyzing Masterpiece..." : "Crafting Visuals..."}
              </h2>
              <p className="text-slate-400 mt-2">
                Gemini is processing your request to create high-quality 16:9 variants.
              </p>
            </div>
          </div>
        )}

        {/* Error State */}
        {state.status === AppStatus.ERROR && (
          <div className="bg-red-500/10 border border-red-500/50 p-6 rounded-2xl text-center">
            <h3 className="text-red-400 font-bold text-lg mb-2">Processing Error</h3>
            <p className="text-red-200/70 mb-6">{state.error}</p>
            <Button onClick={() => setState(prev => ({ ...prev, status: AppStatus.IDLE }))} variant="danger">Dismiss</Button>
          </div>
        )}
      </main>

      {/* Footer Info */}
      <footer className="mt-20 border-t border-slate-800 pt-8 text-center text-slate-500 text-sm">
        <p>Powered by Gemini 3 Flash & 2.5 Flash Image Generation</p>
        <div className="mt-2 flex justify-center gap-4">
          <span>Vision Analysis</span>
          <span>•</span>
          <span>16:9 Cinematic Aspect</span>
          <span>•</span>
          <span>Dual Variants</span>
        </div>
      </footer>
    </div>
  );
};

// Reusable results grid component
const ResultsGrid: React.FC<{ status: AppStatus, variants: GeneratedImage[] }> = ({ status, variants }) => {
  if (status !== AppStatus.SUCCESS || variants.length === 0) return null;

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
      {variants.map((variant, index) => (
        <div key={variant.id} className="glass-panel rounded-3xl overflow-hidden group">
          <div className="relative aspect-video bg-slate-900">
             <img 
              src={variant.url} 
              alt={`Variant ${index + 1}`} 
              className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" 
            />
            <div className="absolute top-4 left-4">
              <span className="px-3 py-1 bg-black/50 backdrop-blur-md rounded-full text-xs font-bold text-white border border-white/20">
                VARIATION {index + 1}
              </span>
            </div>
          </div>
          <div className="p-4 flex justify-between items-center">
            <span className="text-slate-400 text-sm">AI Generated (16:9)</span>
            <div className="flex gap-2">
              <a 
                href={variant.url} 
                download={`variant-${index + 1}.png`}
                className="text-blue-400 hover:text-blue-300 transition-colors p-2 hover:bg-white/5 rounded-lg"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                </svg>
              </a>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

export default App;

export interface GeneratedImage {
  url: string;
  id: string;
}

export enum AppStatus {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  ANALYZING = 'ANALYZING',
  GENERATING = 'GENERATING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

export type ActiveTab = 'vision' | 'text';

export interface ImageStyle {
  id: string;
  name: string;
  promptSuffix: string;
  icon: string;
}

export const POPULAR_STYLES: ImageStyle[] = [
  { id: 'none', name: 'Original', promptSuffix: '', icon: '✨' },
  { id: 'cinematic', name: 'Cinematic', promptSuffix: 'cinematic lighting, hyper-realistic, 8k, wide angle lens, highly detailed', icon: '🎬' },
  { id: 'anime', name: 'Anime', promptSuffix: 'studio ghibli style, vibrant colors, clean lines, anime aesthetic', icon: '🌸' },
  { id: 'digital_art', name: 'Digital Art', promptSuffix: 'trending on artstation, sharp focus, intricate details, vivid colors', icon: '🎨' },
  { id: 'oil_painting', name: 'Oil Painting', promptSuffix: 'classical oil painting, textured brushstrokes, rich colors, canvas texture', icon: '🖌️' },
  { id: 'cyberpunk', name: 'Cyberpunk', promptSuffix: 'neon lights, futuristic, urban atmosphere, synthwave colors, high tech', icon: '🌃' },
  { id: '3d_render', name: '3D Render', promptSuffix: 'octane render, unreal engine 5, soft shadows, volumetric lighting, plastic texture', icon: '🧊' },
  { id: 'watercolor', name: 'Watercolor', promptSuffix: 'soft watercolor textures, artistic splatters, paper texture, delicate washes', icon: '💧' },
];

export interface AppState {
  originalImage: string | null;
  imageZoom: number;
  extractedPrompt: string;
  manualPrompt: string;
  selectedStyleId: string;
  variants: GeneratedImage[];
  status: AppStatus;
  error: string | null;
  activeTab: ActiveTab;
}

import React, { useState } from 'react';
import { AppStatus, AppState, GeneratedImage, ActiveTab, POPULAR_STYLES } from './types';
import { fileToDataUrl, extractPromptFromImage, generateImageVariant } from './services/geminiService';
import { Button } from './components/Button';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    originalImage: null,
    imageZoom: 1,
    extractedPrompt: '',
    manualPrompt: '',
    selectedStyleId: 'cinematic',
    variants: [],
    status: AppStatus.IDLE,
    error: null,
    activeTab: 'vision',
  });

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      setState(prev => ({ ...prev, status: AppStatus.UPLOADING, error: null }));
      const dataUrl = await fileToDataUrl(file);
      setState(prev => ({ 
        ...prev, 
        originalImage: dataUrl, 
        imageZoom: 1,
        status: AppStatus.IDLE 
      }));
    } catch (err) {
      setState(prev => ({ 
        ...prev, 
        status: AppStatus.ERROR, 
        error: "Failed to load image. Please try again." 
      }));
    }
  };

  const adjustZoom = (delta: number) => {
    setState(prev => ({
      ...prev,
      imageZoom: Math.max(0.5, Math.min(5, prev.imageZoom + delta))
    }));
  };

  const resetZoom = () => {
    setState(prev => ({ ...prev, imageZoom: 1 }));
  };

  const getStyleSuffix = (styleId: string) => {
    const style = POPULAR_STYLES.find(s => s.id === styleId);
    return style ? style.promptSuffix : '';
  };

  const processVisionary = async () => {
    if (!state.originalImage) return;

    try {
      setState(prev => ({ ...prev, status: AppStatus.ANALYZING, error: null, variants: [] }));
      const prompt = await extractPromptFromImage(state.originalImage);

      setState(prev => ({ ...prev, extractedPrompt: prompt, status: AppStatus.GENERATING }));

      const styleSuffix = getStyleSuffix(state.selectedStyleId);

      const variantPromises = [
        generateImageVariant(prompt, styleSuffix),
        generateImageVariant(prompt, styleSuffix + ", alternative lighting and perspective")
      ];

      const [v1, v2] = await Promise.all(variantPromises);

      const newVariants: GeneratedImage[] = [
        { id: 'v1', url: v1 },
        { id: 'v2', url: v2 }
      ];

      setState(prev => ({ 
        ...prev, 
        variants: newVariants, 
        status: AppStatus.SUCCESS 
      }));

    } catch (err: any) {
      console.error(err);
      setState(prev => ({ 
        ...prev, 
        status: AppStatus.ERROR, 
        error: err.message || "An unexpected error occurred during processing." 
      }));
    }
  };

  const processCreative = async () => {
    if (!state.manualPrompt.trim()) return;

    try {
      setState(prev => ({ ...prev, status: AppStatus.GENERATING, error: null, variants: [] }));

      const styleSuffix = getStyleSuffix(state.selectedStyleId);

      const variantPromises = [
        generateImageVariant(state.manualPrompt, styleSuffix),
        generateImageVariant(state.manualPrompt, styleSuffix + ", slightly different interpretation")
      ];

      const [v1, v2] = await Promise.all(variantPromises);

      const newVariants: GeneratedImage[] = [
        { id: 'v1', url: v1 },
        { id: 'v2', url: v2 }
      ];

      setState(prev => ({ 
        ...prev, 
        variants: newVariants, 
        status: AppStatus.SUCCESS 
      }));

    } catch (err: any) {
      console.error(err);
      setState(prev => ({ 
        ...prev, 
        status: AppStatus.ERROR, 
        error: err.message || "An unexpected error occurred during generation." 
      }));
    }
  };

  const resetApp = () => {
    setState(prev => ({
      ...prev,
      originalImage: null,
      imageZoom: 1,
      extractedPrompt: '',
      manualPrompt: '',
      selectedStyleId: 'cinematic',
      variants: [],
      status: AppStatus.IDLE,
      error: null,
    }));
  };

  const setTab = (tab: ActiveTab) => {
    setState(prev => ({ ...prev, activeTab: tab, status: AppStatus.IDLE, variants: [], error: null }));
  };

  return (
    <div className="min-h-screen pb-12">
      {/* Header */}
      <header className="relative py-8 px-4 text-center">
        {(state.originalImage || state.variants.length > 0 || state.manualPrompt) && (
          <div className="absolute top-8 right-4 md:right-8">
            <Button 
              onClick={resetApp} 
              variant="secondary" 
              className="text-xs px-3 py-1.5 opacity-70 hover:opacity-100"
            >
              <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
              </svg>
              Reset App
            </Button>
          </div>
        )}
        <h1 className="text-4xl md:text-5xl font-bold bg-gradient-to-r from-blue-400 via-purple-400 to-emerald-400 bg-clip-text text-transparent">
          G-Image Studio
        </h1>
        <p className="mt-4 text-slate-400 max-w-2xl mx-auto text-lg">
          Transform your ideas into 16:9 cinematic visuals using advanced AI.
        </p>
      </header>

      {/* Tabs */}
      <nav className="max-w-md mx-auto mb-10 px-4">
        <div className="flex p-1 bg-slate-800/50 backdrop-blur-md border border-slate-700 rounded-2xl">
          <button 
            onClick={() => setTab('vision')}
            className={`flex-1 py-2.5 rounded-xl text-sm font-semibold transition-all duration-300 ${state.activeTab === 'vision' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
          >
            Visionary Re-Imagine
          </button>
          <button 
            onClick={() => setTab('text')}
            className={`flex-1 py-2.5 rounded-xl text-sm font-semibold transition-all duration-300 ${state.activeTab === 'text' ? 'bg-purple-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
          >
            Creative Prompt
          </button>
        </div>
      </nav>

      {/* Style Selector - Shared between modes */}
      <section className="max-w-6xl mx-auto px-4 mb-8">
        <h3 className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
          Choose Your Style
        </h3>
        <div className="flex gap-4 overflow-x-auto pb-4 scrollbar-hide">
          {POPULAR_STYLES.map((style) => (
            <button
              key={style.id}
              onClick={() => setState(prev => ({ ...prev, selectedStyleId: style.id }))}
              className={`flex-shrink-0 px-5 py-3 rounded-2xl border transition-all duration-200 flex items-center gap-2 ${
                state.selectedStyleId === style.id 
                  ? 'bg-blue-600 border-blue-400 text-white shadow-lg shadow-blue-500/20' 
                  : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-500 hover:text-slate-200'
              }`}
            >
              <span className="text-xl">{style.icon}</span>
              <span className="font-medium whitespace-nowrap">{style.name}</span>
            </button>
          ))}
        </div>
      </section>

      <main className="max-w-6xl mx-auto px-4 space-y-8">

        {/* TAB 1: VISIONARY RE-IMAGINE */}
        {state.activeTab === 'vision' && (
          <div className="space-y-8">
            {state.status === AppStatus.IDLE && !state.originalImage && (
              <div className="flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-3xl p-12 glass-panel transition-all hover:border-blue-500/50">
                <div className="w-16 h-16 bg-blue-500/10 rounded-full flex items-center justify-center mb-6">
                  <svg className="w-8 h-8 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                </div>
                <h2 className="text-xl font-semibold mb-2">Image to Prompt</h2>
                <p className="text-slate-500 mb-6">Upload an image to extract its style and generate variants</p>
                <input 
                  type="file" 
                  accept="image/*" 
                  onChange={handleImageUpload} 
                  className="hidden" 
                  id="image-upload" 
                />
                <label htmlFor="image-upload">
                  <Button as="span" className="cursor-pointer">Select Image</Button>
                </label>
              </div>
            )}

            {(state.originalImage || state.status === AppStatus.SUCCESS) && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Original View */}
                <div className="glass-panel rounded-3xl p-6 h-fit sticky top-8">
                  <h3 className="text-lg font-semibold mb-4 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="w-2 h-2 bg-blue-500 rounded-full"></span>
                      Original Input
                    </div>
                    {/* Zoom Controls Overlay */}
                    <div className="flex items-center bg-slate-800/80 rounded-lg p-1 border border-slate-700 backdrop-blur-sm">
                      <button 
                        onClick={() => adjustZoom(-0.1)} 
                        className="p-1 hover:bg-slate-700 rounded transition-colors"
                        title="Zoom Out"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 12H4" />
                        </svg>
                      </button>
                      <span className="text-[10px] font-mono w-10 text-center text-slate-300">
                        {Math.round(state.imageZoom * 100)}%
                      </span>
                      <button 
                        onClick={() => adjustZoom(0.1)} 
                        className="p-1 hover:bg-slate-700 rounded transition-colors"
                        title="Zoom In"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
                        </svg>
                      </button>
                      <button 
                        onClick={resetZoom} 
                        className="ml-1 p-1 hover:bg-slate-700 rounded transition-colors text-blue-400"
                        title="Reset Zoom"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                        </svg>
                      </button>
                    </div>
                  </h3>
                  <div className="rounded-2xl overflow-hidden shadow-2xl bg-slate-900 border border-slate-700 relative group cursor-zoom-in">
                    <img 
                      src={state.originalImage!} 
                      alt="Original" 
                      className="w-full object-cover transition-transform duration-200 ease-out origin-center" 
                      style={{ transform: `scale(${state.imageZoom})` }}
                    />
                  </div>

                  {state.status === AppStatus.IDLE && (
                    <div className="mt-6 space-y-3">
                      <Button onClick={processVisionary} className="w-full">
                        Analyze & Generate
                      </Button>
                    </div>
                  )}

                  {state.extractedPrompt && (
                    <div className="mt-6 p-4 rounded-xl bg-slate-900/50 border border-slate-700">
                      <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Decoded Prompt</p>
                      <p className="text-sm text-slate-300 leading-relaxed italic">
                        "{state.extractedPrompt}"
                      </p>
                    </div>
                  )}
                </div>

                {/* Results View */}
                <div className="lg:col-span-2">
                  <ResultsGrid status={state.status} variants={state.variants} />
                </div>
              </div>
            )}
          </div>
        )}

        {/* TAB 2: CREATIVE PROMPT */}
        {state.activeTab === 'text' && (
          <div className="space-y-8">
            <div className="glass-panel rounded-3xl p-8 max-w-3xl mx-auto border border-purple-500/20 shadow-xl shadow-purple-500/5">
              <h2 className="text-xl font-bold mb-4 flex items-center gap-3">
                <span className="p-2 bg-purple-500/10 rounded-lg">
                  <svg className="w-5 h-5 text-purple-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                  </svg>
                </span>
                Text to Image
              </h2>
              <textarea 
                placeholder="Describe what you want to see... e.g., 'A futuristic cyberpunk marketplace with neon signs and flying cars in heavy rain'"
                className="w-full h-32 bg-slate-900/50 border border-slate-700 rounded-2xl p-4 text-slate-200 focus:outline-none focus:ring-2 focus:ring-purple-500/50 resize-none transition-all"
                value={state.manualPrompt}
                onChange={(e) => setState(prev => ({ ...prev, manualPrompt: e.target.value }))}
                disabled={state.status === AppStatus.GENERATING}
              />
              <div className="mt-6 flex justify-end">
                <Button 
                  onClick={processCreative} 
                  disabled={!state.manualPrompt.trim()}
                  isLoading={state.status === AppStatus.GENERATING}
                  className="bg-purple-600 hover:bg-purple-500"
                >
                  Generate Variants
                </Button>
              </div>
            </div>

            {state.status === AppStatus.SUCCESS && state.variants.length > 0 && (
              <div className="pt-4">
                 <ResultsGrid status={state.status} variants={state.variants} />
              </div>
            )}
          </div>
        )}

        {/* Shared Processing State Overlay */}
        {(state.status === AppStatus.ANALYZING || state.status === AppStatus.GENERATING) && (
          <div className="glass-panel rounded-3xl p-12 text-center space-y-6 animate-pulse border-blue-500/20">
            <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto shadow-lg shadow-blue-500/20"></div>
            <div>
              <h2 className="text-2xl font-bold text-blue-400">
                {state.status === AppStatus.ANALYZING ? "Analyzing Masterpiece..." : "Crafting Visuals..."}
              </h2>
              <p className="text-slate-400 mt-2">
                Gemini is processing your request to create high-quality 16:9 variants.
              </p>
            </div>
          </div>
        )}

        {/* Error State */}
        {state.status === AppStatus.ERROR && (
          <div className="bg-red-500/10 border border-red-500/50 p-6 rounded-2xl text-center">
            <h3 className="text-red-400 font-bold text-lg mb-2">Processing Error</h3>
            <p className="text-red-200/70 mb-6">{state.error}</p>
            <Button onClick={() => setState(prev => ({ ...prev, status: AppStatus.IDLE }))} variant="danger">Dismiss</Button>
          </div>
        )}
      </main>

      {/* Footer Info */}
