      setState(prev => ({ ...prev, status: AppStatus.UPLOADING, error: null }));
      const dataUrl = await fileToDataUrl(file);
      setState(prev => ({ 
        ...prev, 
        originalImage: dataUrl, 
        imageZoom: 1,
        extractedPrompt: '',
        variants: [],
        status: AppStatus.IDLE 
      }));
