    if (!state.extractedPrompt) return;

    try {
      setState(prev => ({ ...prev, status: AppStatus.GENERATING, error: null }));

      const styleSuffix = getStyleSuffix(state.selectedStyleId);

      const variantPromises = [
        generateImageVariant(state.extractedPrompt, styleSuffix),
        generateImageVariant(state.extractedPrompt, styleSuffix + ", alternative lighting and perspective")
      ];

