    setState(prev => ({
      ...prev,
      originalImage: null,
      imageZoom: 1,
      extractedPrompt: '',
      manualPrompt: '',
      selectedStyleId: 'cinematic',
      variants: [],
      status: AppStatus.IDLE,
      error: null,
